def create_tnbts_map(
    show_kawasan, show_desa_geojson, show_kabupaten, show_batas_tnbts, show_tanaman,
    gdf_desa, gdf_kabupaten, gdf_batas, df_tanaman_filtered
):
    m = folium.Map(
        location=[-7.955, 112.953],
        zoom_start=11,
        tiles='OpenStreetMap',
        name='OpenStreetMap'
    )

    # Tile tambahan
    folium.TileLayer(
        tiles='https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',
        attr='Esri', name='🛰️ Satelit'
    ).add_to(m)
    folium.TileLayer(
        tiles='https://{s}.tile.opentopomap.org/{z}/{x}/{y}.png',
        attr='OpenTopoMap', name='🗻 Terrain'
    ).add_to(m)

    # ── LAYER 1: Batas TNBTS (outline tebal, fill no color) ─────────────────
    if show_batas_tnbts and not gdf_batas.empty:
        batas_group = folium.FeatureGroup(name='🔲 Batas TNBTS', show=True)

        folium.GeoJson(
            gdf_batas,
            name='Batas TNBTS',
            style_function=lambda f: {
                'fillColor': 'none',
                'color': '#B71C1C',
                'weight': 4,
                'fillOpacity': 0,
                'opacity': 1,
                'dashArray': '8, 4',
            },
            highlight_function=lambda f: {
                'fillColor': '#B71C1C',
                'color': '#7F0000',
                'weight': 5,
                'fillOpacity': 0.10,
            },
            tooltip=folium.GeoJsonTooltip(
                fields=['Keterangan'],
                aliases=['Keterangan:'],
                localize=False,
                sticky=False,
                style=(
                    'background-color:white;'
                    'border:2px solid #B71C1C;'
                    'border-radius:6px;'
                    'padding:6px 10px;'
                    'font-family:Arial;'
                    'font-size:12px;'
                    'font-weight:bold;'
                    'color:#B71C1C;'
                    'box-shadow:2px 2px 6px rgba(0,0,0,.15);'
                    'pointer-events:none;'
                ),
            ),
            popup=folium.GeoJsonPopup(
                fields=['Keterangan'],
                aliases=[''],
                max_width=300
            )
        ).add_to(batas_group)
        batas_group.add_to(m)

    # ── LAYER 2: Batas Kabupaten (outline tebal, fill no color, label) ─────
    if show_kabupaten and not gdf_kabupaten.empty:
        kabupaten_group = folium.FeatureGroup(name='🗺️ Batas Kabupaten', show=True)

        folium.GeoJson(
            gdf_kabupaten,
            name='Kabupaten',
            style_function=lambda f: {
                'fillColor': 'none',
                'color': '#1565C0',
                'weight': 4,
                'fillOpacity': 0,
                'opacity': 1,
                'dashArray': '',
            },
            highlight_function=lambda f: {
                'fillColor': '#1565C0',
                'color': '#0D47A1',
                'weight': 5,
                'fillOpacity': 0.12,
            },
            tooltip=folium.GeoJsonTooltip(
                fields=['nama_kabko', 'nama_provi'],
                aliases=['Kabupaten:', 'Provinsi:'],
                localize=False,
                sticky=False,
                style=(
                    'background-color:white;'
                    'border:1px solid #1565C0;'
                    'border-radius:6px;'
                    'padding:6px 10px;'
                    'font-family:Arial;'
                    'font-size:12px;'
                    'box-shadow:2px 2px 6px rgba(0,0,0,.15);'
                    'pointer-events:none;'
                ),
            ),
            popup=folium.GeoJsonPopup(
                fields=['nama_kabko', 'nama_provi'],
                aliases=['Kabupaten', 'Provinsi'],
                max_width=250
            )
        ).add_to(kabupaten_group)

        # Label nama kabupaten menggunakan DivIcon di centroid masing-masing
        import geopandas as _gpd
        for _, row_kab in gdf_kabupaten.iterrows():
            try:
                centroid = row_kab.geometry.centroid
                nama_kab = row_kab.get('nama_kabko', '')
                folium.Marker(
                    location=[centroid.y, centroid.x],
                    icon=folium.DivIcon(
                        html=f"""<div style="
                            font-family: Arial, sans-serif;
                            font-size: 12px;
                            font-weight: bold;
                            color: #1565C0;
                            background: rgba(255,255,255,0.85);
                            border: 2px solid #1565C0;
                            border-radius: 5px;
                            padding: 3px 7px;
                            white-space: nowrap;
                            box-shadow: 1px 1px 4px rgba(0,0,0,0.2);
                            text-transform: uppercase;
                            letter-spacing: 0.5px;
                        ">{nama_kab}</div>""",
                        icon_size=(150, 28),
                        icon_anchor=(75, 14),
                    )
                ).add_to(kabupaten_group)
            except Exception:
                pass

        kabupaten_group.add_to(m)

    # ── LAYER 3: Batas Desa (outline tebal, fill no color) ──────────────────
    # DAN Label Desa pada centroid (perbaikan utama)
    if show_desa_geojson and not gdf_desa.empty:
        desa_group = folium.FeatureGroup(name='🏘️ Batas Desa', show=True)
        available_fields, field_aliases = [], []
        for col, alias in [
            ('nama_kelur','Desa:'),('nama_kecam','Kecamatan:'),
            ('nama_kabko','Kabupaten:'),('jumlah_pen','Penduduk:')
        ]:
            if col in gdf_desa.columns:
                available_fields.append(col)
                field_aliases.append(alias)

        folium.GeoJson(
            gdf_desa,
            name='Desa',
            style_function=lambda f: {
                'fillColor':'none',
                'color':'#e65100',
                'weight':2.5,
                'fillOpacity':0,
                'opacity':1,
            },
            highlight_function=lambda f: {
                'fillColor':'#ff6d00',
                'color':'#bf360c',
                'weight':3.5,
                'fillOpacity':0.15,
            },
            tooltip=folium.GeoJsonTooltip(
                fields=available_fields, aliases=field_aliases),
            popup=folium.GeoJsonPopup(
                fields=available_fields,
                aliases=field_aliases,
                max_width=300
            )
        ).add_to(desa_group)
        
         # ===== PERBAIKAN UTAMA: Menambahkan Label untuk Batas Desa =====
        # Label nama desa menggunakan DivIcon di centroid masing-masing polygon desa
        # Format: NAMA_DESA - NAMA_KABUPATEN
        for _, row_desa in gdf_desa.iterrows():
            try:
                # Hitung centroid polygon desa
                centroid = row_desa.geometry.centroid
                # Ambil nama desa dan kabupaten
                nama_desa = row_desa.get('nama_kelur', '')
                nama_kabupaten = row_desa.get('nama_kabko', '')
                
                # Format label: DESA - KABUPATEN
                if nama_desa and nama_kabupaten:
                    label_text = f"{nama_desa.upper()} - {nama_kabupaten.upper()}"
                elif nama_desa:
                    label_text = nama_desa.upper()
                else:
                    label_text = ""
                
                # Hanya tambahkan marker jika label_text tidak kosong
                if label_text:
                    # Sesuaikan ukuran ikon berdasarkan panjang teks (opsional)
                    # Panjang teks diperkirakan, bisa disesuaikan
                    text_length = len(label_text)
                    # Lebar ikon: 8px per karakter + 20px padding
                    icon_width = max(140, text_length * 8 + 20)
                    icon_height = 24
                    
                    folium.Marker(
                        location=[centroid.y, centroid.x],
                        icon=folium.DivIcon(
                            html=f"""<div style="
                                font-family: Arial, sans-serif;
                                font-size: 10px;
                                font-weight: bold;
                                color: #e65100;
                                background: rgba(255,255,255,0.9);
                                border: 1.5px solid #e65100;
                                border-radius: 4px;
                                padding: 3px 6px;
                                white-space: nowrap;
                                box-shadow: 1px 1px 3px rgba(0,0,0,0.15);
                                letter-spacing: 0.3px;
                                text-align: center;
                            ">{label_text}</div>""",
                            icon_size=(icon_width, icon_height),
                            icon_anchor=(icon_width // 2, icon_height // 2),  # Posisikan di tengah centroid
                        )
                    ).add_to(desa_group)
            except Exception as e:
                # Lewati jika ada error pada geometry (misalnya MultiPolygon yang kompleks)
                pass
        # ================================================================

        desa_group.add_to(m)


    # ── LAYER 5: Sebaran Tanaman Herbal ──────────────────────────────────────
    if show_tanaman and not df_tanaman_filtered.empty:
        tanaman_group = folium.FeatureGroup(name='🌿 Sebaran Tanaman Herbal', show=True)

        for _, row in df_tanaman_filtered.iterrows():
            mk_color = JENIS_COLOR.get(row['jenis'], 'blue')
            kw_color = KAWASAN_HEX.get(row['kawasan'], '#555555')

            popup_html = f"""
            <div style="font-family:Arial;min-width:270px;max-width:300px;padding:4px;">
                <div style="background:{kw_color};color:white;padding:8px 10px;
                            border-radius:6px 6px 0 0;margin:-4px -4px 8px -4px;">
                    <b style="font-size:15px;">🌿 {row['nama_tanaman']}</b><br>
                    <i style="font-size:11px;opacity:.85;">{row['nama_latin']}</i>
                </div>
                <table style="font-size:12px;width:100%;border-collapse:collapse;">
                    <tr style="background:#f9fbe7;">
                        <td style="padding:4px 6px;font-weight:bold;color:#555;width:90px;">Jenis</td>
                        <td style="padding:4px 6px;">{row['jenis']}</td>
                    </tr>
                    <tr>
                        <td style="padding:4px 6px;font-weight:bold;color:#555;">Fungsi</td>
                        <td style="padding:4px 6px;color:#1a6b2a;font-weight:600;">{row['fungsi_utama']}</td>
                    </tr>
                    <tr style="background:#f9fbe7;">
                        <td style="padding:4px 6px;font-weight:bold;color:#555;">Kawasan</td>
                        <td style="padding:4px 6px;">
                            <span style="background:{kw_color};color:white;padding:2px 7px;
                                         border-radius:12px;font-size:10px;">{row['kawasan']}</span>
                        </td>
                    </tr>
                    <tr>
                        <td style="padding:4px 6px;font-weight:bold;color:#555;">Lokasi</td>
                        <td style="padding:4px 6px;">{row['lokasi_detail']}</td>
                    </tr>
                    <tr style="background:#f9fbe7;">
                        <td style="padding:4px 6px;font-weight:bold;color:#555;">Desa</td>
                        <td style="padding:4px 6px;">{row['desa']}</td>
                    </tr>
                    <tr>
                        <td style="padding:4px 6px;font-weight:bold;color:#555;">Ketinggian</td>
                        <td style="padding:4px 6px;">⛰️ {row['ketinggian']:,} mdpl</td>
                    </tr>
                    <tr style="background:#f9fbe7;">
                        <td style="padding:4px 6px;font-weight:bold;color:#555;">Status</td>
                        <td style="padding:4px 6px;">
                            {'🔒 <b style="color:#c62828;">Dilindungi</b>'
                             if row['status_konservasi'] == 'Dilindungi'
                             else '✅ Umum'}
                        </td>
                    </tr>
                    <tr>
                        <td style="padding:4px 6px;font-weight:bold;color:#555;">Koordinat</td>
                        <td style="padding:4px 6px;font-size:11px;color:#666;">
                            {row['latitude']:.4f}, {row['longitude']:.4f}
                        </td>
                    </tr>
                </table>
            </div>"""

            folium.CircleMarker(
                location=[row['latitude'], row['longitude']],
                radius=7,
                popup=folium.Popup(popup_html, max_width=310),
                tooltip=(
                    f"🌿 <b>{row['nama_tanaman']}</b> ({row['jenis']})<br>"
                    f"<small>{row['kawasan']}</small>"
                ),
                color=mk_color,
                fill=True,
                fillColor=mk_color,
                fillOpacity=0.90,
                weight=2
            ).add_to(tanaman_group)

        tanaman_group.add_to(m)


    # Layer control & plugins
    folium.LayerControl(collapsed=False).add_to(m)
    try:
        from folium.plugins import Fullscreen
        Fullscreen(position='topright').add_to(m)
    except Exception:
        pass
    try:
        from folium.plugins import MeasureControl
        MeasureControl(position='bottomright',
                       primary_length_unit='kilometers').add_to(m)
    except Exception:
        pass

    return m


